"use client";

import { type PanelProps, Panel as PanelRoot } from "./panel";
import { PanelContent, type PanelContentProps, panelContentVariants } from "./panel-content";
import { PanelDescription, type PanelDescriptionProps } from "./panel-description";
import { PanelFooter, type PanelFooterProps } from "./panel-footer";
import { PanelHeader, type PanelHeaderProps } from "./panel-header";
import { PanelLabel, type PanelLabelProps } from "./panel-label";
import { PanelRow, type PanelRowProps } from "./panel-row";
import { PanelTitle, type PanelTitleProps } from "./panel-title";

/**
 * Root container. Polymorphic via `as` (div, article, section, aside). A statically discoverable
 * Panel.Title or explicit ARIA name switches the initial render to <section>. Opaque title or
 * description wrappers require stable part ids plus root aria-labelledby/aria-describedby for SSR.
 */
const Panel = Object.assign(PanelRoot, {
  Header: PanelHeader,
  Title: PanelTitle,
  Description: PanelDescription,
  Content: PanelContent,
  Row: PanelRow,
  Footer: PanelFooter,
  Label: PanelLabel,
});

export { Panel, type PanelProps };
export { PanelHeader, type PanelHeaderProps };
export { PanelTitle, type PanelTitleProps };
export { PanelDescription, type PanelDescriptionProps };
export { PanelContent, type PanelContentProps, panelContentVariants };
export { PanelFooter, type PanelFooterProps };
export { PanelRow, type PanelRowProps };
export { PanelLabel, type PanelLabelProps };

"use client";

import {
  Children,
  type ComponentPropsWithRef,
  type ElementType,
  isValidElement,
  type ReactNode,
  useCallback,
  useId,
  useMemo,
  useState,
} from "react";
import { cn } from "@/lib/utils";
import { PanelContext, type PanelContextValue } from "./panel-context";
import { PanelDescription } from "./panel-description";
import { PanelTitle } from "./panel-title";

export type PanelElement = "div" | "article" | "section" | "aside";

/** Allowed panel frame values. */
export type PanelFrame = "hairline" | "rail" | "viewfinder" | "surface";
/** Allowed panel tone values. */
export type PanelTone = "info" | "success" | "warning" | "error" | "accent";
/** Allowed panel density values. */
export type PanelDensity = "default" | "compact";

interface PanelOwnProps {
  /**
   * Visual chrome. Hairline = soft border + marker bar; rail = inline-start rail only;
   * viewfinder = corner brackets; surface = elevated --surface-1 background.
   */
  frame?: PanelFrame;
  /**
   * Border-color tint. Visual cue only - no semantic role, no live announcement. Use Callout
   * for real status messaging.
   */
  tone?: PanelTone;
  /** Padding rhythm. Default = 14/20; compact = 10/14. */
  density?: PanelDensity;
}

/** Props for panel. */
export type PanelProps<T extends PanelElement = "div"> = Omit<
  ComponentPropsWithRef<T>,
  keyof PanelOwnProps | "as"
> &
  PanelOwnProps & {
    as?: T;
  };

/**
 * Root container. Polymorphic via `as` (div, article, section, aside). A statically discoverable
 * Panel.Title or an explicit ARIA name switches the initial render to <section>. When an opaque
 * child component creates the title or description, give those parts stable ids and pass
 * aria-labelledby/aria-describedby to Panel so the server-rendered root is wired.
 */
export function Panel<T extends PanelElement = "div">(props: PanelProps<T>) {
  const {
    as,
    ref,
    className,
    frame,
    tone,
    density,
    children,
    "aria-label": ariaLabel,
    "aria-labelledby": ariaLabelledBy,
    "aria-describedby": ariaDescribedBy,
    ...rest
  } = props as PanelProps<PanelElement>;

  const id = useId();
  const titleId = `${id}-title`;
  const descriptionId = `${id}-description`;

  // Registration (consumer id wins) covers titles wrapped in layout/consumer
  // components; the static child scan seeds SSR and the first client render.
  const [registeredTitleId, setRegisteredTitleId] = useState<string | null>(null);
  const [registeredDescriptionId, setRegisteredDescriptionId] = useState<string | null>(null);

  const registerTitle = useCallback((nextId: string) => setRegisteredTitleId(nextId), []);
  const unregisterTitle = useCallback(
    (nextId: string) => setRegisteredTitleId((current) => (current === nextId ? null : current)),
    [],
  );
  const registerDescription = useCallback(
    (nextId: string) => setRegisteredDescriptionId(nextId),
    [],
  );
  const unregisterDescription = useCallback(
    (nextId: string) =>
      setRegisteredDescriptionId((current) => (current === nextId ? null : current)),
    [],
  );

  const contextValue = useMemo<PanelContextValue>(
    () => ({
      titleId,
      descriptionId,
      registerTitle,
      unregisterTitle,
      registerDescription,
      unregisterDescription,
    }),
    [
      titleId,
      descriptionId,
      registerTitle,
      unregisterTitle,
      registerDescription,
      unregisterDescription,
    ],
  );

  const resolvedTitleId = registeredTitleId ?? findPanelChildId(children, PanelTitle, titleId);
  const resolvedDescriptionId =
    registeredDescriptionId ?? findPanelChildId(children, PanelDescription, descriptionId);
  const hasRenderableTitle = resolvedTitleId !== null;
  const hasAriaName = isNonEmptyString(ariaLabel) || isNonEmptyString(ariaLabelledBy);
  const isNamedRegion = hasRenderableTitle || hasAriaName;

  const resolvedFrame = frame ?? "hairline";
  const resolvedDensity = density ?? "default";
  const Tag = (as ?? (isNamedRegion ? "section" : "div")) as ElementType;

  const accessibleName = resolvePanelAccessibleName({
    ariaLabel,
    ariaLabelledBy,
    titleId: resolvedTitleId ?? titleId,
    hasRenderableTitle,
  });
  const resolvedAriaDescribedBy = mergeAriaIds(ariaDescribedBy, resolvedDescriptionId);

  return (
    <PanelContext value={contextValue}>
      <Tag
        {...rest}
        ref={ref}
        data-slot="panel"
        data-frame={resolvedFrame}
        data-tone={tone ?? undefined}
        data-density={resolvedDensity}
        aria-label={accessibleName["aria-label"]}
        aria-labelledby={accessibleName["aria-labelledby"]}
        aria-describedby={resolvedAriaDescribedBy}
        className={cn(className)}
      >
        {resolvedFrame === "viewfinder" ? (
          <span aria-hidden="true" data-slot="panel-corners">
            <span className="vf-tl" />
            <span className="vf-tr" />
            <span className="vf-bl" />
            <span className="vf-br" />
          </span>
        ) : null}
        {children}
      </Tag>
    </PanelContext>
  );
}

function isNonEmptyString(value: unknown): value is string {
  return typeof value === "string" && value.trim().length > 0;
}

// Resolved id of the first PanelTitle/PanelDescription in the tree (consumer id
// wins), used to seed aria wiring before registration effects run.
function findPanelChildId(
  children: ReactNode,
  target: typeof PanelTitle | typeof PanelDescription,
  fallbackId: string,
): string | null {
  for (const child of Children.toArray(children)) {
    if (!isValidElement<{ id?: unknown; children?: ReactNode }>(child)) continue;
    if (child.type === target) {
      return typeof child.props.id === "string" ? child.props.id : fallbackId;
    }
    // Nested <Panel> subtrees own their own PanelContext; their titles/descriptions
    // register only to that inner panel, so the outer root must not claim them.
    if (child.type === Panel) continue;
    const nested = findPanelChildId(child.props.children, target, fallbackId);
    if (nested !== null) return nested;
  }
  return null;
}

function mergeAriaIds(external: string | undefined, ownId: string | null): string | undefined {
  const externalId = isNonEmptyString(external) ? external : undefined;
  if (externalId && ownId) return `${externalId} ${ownId}`;
  return externalId ?? ownId ?? undefined;
}

function resolvePanelAccessibleName({
  ariaLabel,
  ariaLabelledBy,
  titleId,
  hasRenderableTitle,
}: {
  ariaLabel: string | undefined;
  ariaLabelledBy: string | undefined;
  titleId: string;
  hasRenderableTitle: boolean;
}): { "aria-label": string | undefined; "aria-labelledby": string | undefined } {
  if (isNonEmptyString(ariaLabelledBy)) {
    return { "aria-label": undefined, "aria-labelledby": ariaLabelledBy };
  }
  if (isNonEmptyString(ariaLabel)) {
    return { "aria-label": ariaLabel, "aria-labelledby": undefined };
  }
  if (hasRenderableTitle) {
    return { "aria-label": undefined, "aria-labelledby": titleId };
  }
  return { "aria-label": undefined, "aria-labelledby": undefined };
}

"use client";

import { createContext, useContext } from "react";

/** Context value shared by panel. */
export interface PanelContextValue {
  /** Fallback id PanelTitle uses when the consumer does not supply one. */
  titleId: string;
  /** Fallback id PanelDescription uses when the consumer does not supply one. */
  descriptionId: string;
  /** PanelTitle registers its resolved id (consumer id wins) on mount. */
  registerTitle: (id: string) => void;
  /** Unregisters title from panel. */
  unregisterTitle: (id: string) => void;
  /** PanelDescription registers its resolved id on mount. */
  registerDescription: (id: string) => void;
  /** Unregisters description from panel. */
  unregisterDescription: (id: string) => void;
}

/** React context backing panel. */
export const PanelContext = createContext<PanelContextValue | undefined>(undefined);

/** Reads the panel context. */
export function usePanelContext(): PanelContextValue {
  const context = useContext(PanelContext);
  if (!context) {
    throw new Error("Panel compound components must be used within a Panel");
  }
  return context;
}

"use client";

import { Children, type ComponentProps, isValidElement, type ReactNode } from "react";
import { cn } from "@/lib/utils";
import { PanelDescription } from "./panel-description";
import { PanelTitle } from "./panel-title";

/** Props for panel header. */
export interface PanelHeaderProps extends ComponentProps<"div"> {
  /** Toggle the 4px foreground marker bar. Use "none" for rail or custom layouts. */
  marker?: "bar" | "none";
}

/**
 * Compound header. Title and Description live in a left column; any other child (eyebrow span,
 * badge, button) lands in a right slot.
 */
export function PanelHeader({ className, children, marker = "bar", ...props }: PanelHeaderProps) {
  const { bodyChildren, endChildren } = partitionHeaderChildren(children);
  const hasEnd = endChildren.length > 0;

  return (
    <div {...props} data-slot="panel-header" data-marker={marker} className={cn(className)}>
      <div data-slot="panel-header-body">{bodyChildren}</div>
      {hasEnd ? <div data-slot="panel-header-end">{endChildren}</div> : null}
    </div>
  );
}

function isBodyChild(child: ReactNode): boolean {
  if (!isValidElement(child)) return false;
  return child.type === PanelTitle || child.type === PanelDescription;
}

function partitionHeaderChildren(children: ReactNode): {
  bodyChildren: ReactNode[];
  endChildren: ReactNode[];
} {
  const bodyChildren: ReactNode[] = [];
  const endChildren: ReactNode[] = [];
  for (const child of Children.toArray(children)) {
    if (isBodyChild(child)) bodyChildren.push(child);
    else endChildren.push(child);
  }
  return { bodyChildren, endChildren };
}

"use client";

import { type ComponentProps, useLayoutEffect } from "react";
import { cn } from "@/lib/utils";
import { usePanelContext } from "./panel-context";

/** Props for panel title. */
export interface PanelTitleProps extends ComponentProps<"h2"> {
  /** Heading level. Defaults to h2, matching Dialog. */
  as?: "h2" | "h3" | "h4" | "h5" | "h6";
}

/**
 * Real heading (h2 by default, configurable via `as`). Direct child trees are wired to the Panel
 * root on the server and client. A title created inside an opaque wrapper registers after client
 * render; for SSR, give it a stable id and pass that id through Panel aria-labelledby.
 */
export function PanelTitle({ children, className, as: Tag = "h2", id, ...props }: PanelTitleProps) {
  const { titleId, registerTitle, unregisterTitle } = usePanelContext();
  const resolvedId = id ?? titleId;

  useLayoutEffect(() => {
    registerTitle(resolvedId);
    return () => unregisterTitle(resolvedId);
  }, [resolvedId, registerTitle, unregisterTitle]);

  return (
    <Tag
      {...props}
      id={resolvedId}
      data-slot="panel-title"
      className={cn("m-0 text-sm font-bold leading-tight text-foreground", className)}
    >
      {children}
    </Tag>
  );
}

"use client";

import { type ComponentProps, useLayoutEffect } from "react";
import { cn } from "@/lib/utils";
import { usePanelContext } from "./panel-context";

/** Props for panel description. */
export interface PanelDescriptionProps extends ComponentProps<"p"> {}

/**
 * Paragraph description. Direct child trees are wired to the Panel root on the server and client.
 * A description created inside an opaque wrapper registers after client render; for SSR, give it a
 * stable id and pass that id through Panel aria-describedby.
 */
export function PanelDescription({ className, id, ...props }: PanelDescriptionProps) {
  const { descriptionId, registerDescription, unregisterDescription } = usePanelContext();
  const resolvedId = id ?? descriptionId;

  useLayoutEffect(() => {
    registerDescription(resolvedId);
    return () => unregisterDescription(resolvedId);
  }, [resolvedId, registerDescription, unregisterDescription]);

  return (
    <p
      {...props}
      data-slot="panel-description"
      id={resolvedId}
      className={cn("m-0 text-xs leading-normal text-foreground/70", className)}
    />
  );
}

import { cva, type VariantProps } from "class-variance-authority";
import type { ComponentPropsWithRef } from "react";
import { cn } from "@/lib/utils";

/** Class variants for panel content. */
export const panelContentVariants = cva("text-sm text-foreground", {
  variants: {
    spacing: {
      none: "",
      sm: "space-y-2",
      md: "space-y-4",
    },
  },
  defaultVariants: { spacing: "md" },
});

/** Props for panel content. */
export type PanelContentProps = ComponentPropsWithRef<"div"> &
  VariantProps<typeof panelContentVariants>;

/** Padded content area with configurable inner spacing. */
export function PanelContent({ className, spacing, ...props }: PanelContentProps) {
  return (
    <div
      {...props}
      data-slot="panel-content"
      className={cn(panelContentVariants({ spacing }), className)}
    />
  );
}

import type { ComponentProps, ReactNode } from "react";
import { cn } from "@/lib/utils";

/** Props for panel row. */
export interface PanelRowProps extends Omit<ComponentProps<"div">, "children"> {
  /** Row label (renders left-aligned, muted). */
  label: ReactNode;
  /** Row value (renders right-aligned, foreground). */
  value: ReactNode;
}

/** Key-value row primitive. Adjacent rows get an automatic top divider. */
export function PanelRow({ label, value, className, ...props }: PanelRowProps) {
  return (
    <div {...props} data-slot="panel-row" className={cn("text-xs", className)}>
      <span data-slot="panel-row-label" className="text-muted-foreground">
        {label}
      </span>
      <span data-slot="panel-row-value" className="text-foreground">
        {value}
      </span>
    </div>
  );
}

import type { ComponentPropsWithRef } from "react";
import { cn } from "@/lib/utils";

/** Props for panel footer. */
export type PanelFooterProps = ComponentPropsWithRef<"div">;

/** Bottom metadata/action row. */
export function PanelFooter({ className, ...props }: PanelFooterProps) {
  return (
    <div
      {...props}
      data-slot="panel-footer"
      className={cn("text-xs text-muted-foreground", className)}
    />
  );
}

import type { VariantProps } from "class-variance-authority";
import type { ComponentPropsWithRef } from "react";
import { cornerLabelVariants } from "@/lib/corner-label-variants";
import { cn } from "@/lib/utils";

/** Props for panel label. */
export type PanelLabelProps = ComponentPropsWithRef<"div"> &
  VariantProps<typeof cornerLabelVariants>;

/**
 * Floating corner label (e.g. [ 01 / FS_TREE ]). The Panel root is the positioning context
 * (panel.css sets position: relative on every frame).
 */
export function PanelLabel({ className, variant, ...props }: PanelLabelProps) {
  return (
    <div
      data-slot="panel-label"
      className={cn(cornerLabelVariants({ variant }), className)}
      {...props}
    />
  );
}

/*
 * Panel primitive styles. Three orthogonal axes drive visual chrome via
 * data-attribute selectors on [data-slot="panel"]:
 *   [data-frame]   = hairline | rail | viewfinder | surface
 *   [data-tone]    = info | success | warning | error | accent
 *   [data-density] = default | compact
 *
 * Frame chrome (border, rail, viewfinder corners, surface) is selected by
 * [data-frame]. Tone tints --panel-tone (inherited by the header marker bar)
 * and the frame's color signal (border-color, rail color, corner color, or
 * surface header tint). Density propagates to header/content/footer padding.
 *
 * Adjacent panel-row siblings get an automatic top border for tabular layouts
 * (the rule consumers most commonly hand-rolled).
 */
@layer components {
  /*
   * Default component-token values are consumed via var() fallback (not
   * declared on the slot) so an ancestor-scoped override can reach them.
   * Defaults: --panel-bg → var(--background); --panel-fg → var(--foreground);
   * --panel-hairline → color-mix(in oklab, var(--border) 60%, transparent);
   * --panel-tone → var(--foreground). Tone variants below still win.
   */
  [data-slot="panel"] {
    position: relative;
    background: var(--panel-bg, var(--background));
    color: var(--panel-fg, var(--foreground));
    border-radius: var(--radius);
  }

  /* Density rhythm — single source of truth. */
  [data-slot="panel"][data-density="default"] [data-slot="panel-header"] {
    padding: 14px 20px 12px;
  }
  [data-slot="panel"][data-density="default"] [data-slot="panel-content"] {
    padding: 14px 20px;
  }
  [data-slot="panel"][data-density="default"] [data-slot="panel-footer"] {
    padding: 10px 20px;
  }
  [data-slot="panel"][data-density="compact"] [data-slot="panel-header"] {
    padding: 10px 14px 8px;
  }
  [data-slot="panel"][data-density="compact"] [data-slot="panel-content"] {
    padding: 10px 14px;
  }
  [data-slot="panel"][data-density="compact"] [data-slot="panel-footer"] {
    padding: 8px 14px;
  }

  /* Header. align-items: center so action chips sit on the title's vertical
     center; the marker bar uses align-self: stretch to span full header height. */
  [data-slot="panel-header"] {
    display: flex;
    gap: 12px;
    align-items: center;
  }
  [data-slot="panel-header"][data-marker="bar"]::before {
    content: "";
    flex: none;
    align-self: stretch;
    width: 4px;
    background: var(--panel-tone, var(--foreground));
    border-radius: 1px;
  }
  [data-slot="panel-header"] > [data-slot="panel-header-body"] {
    display: flex;
    flex-direction: column;
    gap: 4px;
    min-width: 0;
    flex: 1 1 auto;
  }
  [data-slot="panel-header"] > [data-slot="panel-header-end"] {
    display: inline-flex;
    align-items: center;
    gap: 8px;
    flex-shrink: 0;
  }

  /* Footer — flex row with space-between for primary text + meta badge. */
  [data-slot="panel-footer"] {
    display: flex;
    align-items: center;
    justify-content: space-between;
    gap: 12px;
  }

  /* Row primitive — adjacent siblings get the auto-divider. */
  [data-slot="panel-row"] {
    display: flex;
    align-items: center;
    justify-content: space-between;
    gap: 12px;
    padding-block: 6px;
  }
  [data-slot="panel-row"] + [data-slot="panel-row"] {
    border-block-start: 1px solid
      var(--panel-hairline, color-mix(in oklab, var(--border) 60%, transparent));
  }

  /* ============================================================
     Frame: hairline (default)
     ============================================================ */
  [data-slot="panel"][data-frame="hairline"] {
    border: 1px solid var(--panel-hairline, color-mix(in oklab, var(--border) 60%, transparent));
  }
  [data-slot="panel"][data-frame="hairline"] [data-slot="panel-header"] {
    border-block-end: 1px solid
      var(--panel-hairline, color-mix(in oklab, var(--border) 60%, transparent));
  }
  [data-slot="panel"][data-frame="hairline"] [data-slot="panel-footer"] {
    border-block-start: 1px solid
      var(--panel-hairline, color-mix(in oklab, var(--border) 60%, transparent));
  }

  /* ============================================================
     Frame: rail — inline-start rail, hairline under header only.
     The rail IS the marker, so suppress the header bar.
     ============================================================ */
  [data-slot="panel"][data-frame="rail"] {
    border: 0;
    border-inline-start: 2px solid var(--border);
    border-radius: 0;
    padding-block: 2px;
  }
  [data-slot="panel"][data-frame="rail"] [data-slot="panel-header"] {
    border-block-end: 1px solid
      var(--panel-hairline, color-mix(in oklab, var(--border) 60%, transparent));
    padding-inline-start: 14px;
  }
  [data-slot="panel"][data-frame="rail"] [data-slot="panel-header"][data-marker="bar"]::before {
    display: none;
  }
  [data-slot="panel"][data-frame="rail"] [data-slot="panel-content"],
  [data-slot="panel"][data-frame="rail"] [data-slot="panel-footer"] {
    padding-inline-start: 14px;
  }
  [data-slot="panel"][data-frame="rail"] [data-slot="panel-footer"] {
    border: 0;
  }

  /* ============================================================
     Frame: viewfinder — four corner brackets. Shares the viewfinder
     visual language with diff-view via the same contract:
       - CSS vars: --viewfinder-size, --viewfinder-weight, --viewfinder-color, --viewfinder-offset
       - Corner element classes: .vf-tl / .vf-tr / .vf-bl / .vf-br
     Dialog uses a separate `.dlg-corners` + [data-corners] pattern
     for its own (in-flow vs. modal) reasons, so there is no literal
     `.viewfinder` class to share across all three components today.
     ============================================================ */
  [data-slot="panel"][data-frame="viewfinder"] {
    --viewfinder-size: 20px;
    --viewfinder-weight: 2px;
    --viewfinder-color: var(--foreground);
    --viewfinder-offset: 0px;
    padding: 8px;
  }
  [data-slot="panel"][data-frame="viewfinder"] [data-slot="panel-corners"] > span {
    position: absolute;
    pointer-events: none;
    width: var(--viewfinder-size);
    height: var(--viewfinder-size);
    border: 0 solid var(--viewfinder-color);
  }
  [data-slot="panel"][data-frame="viewfinder"] [data-slot="panel-corners"] > .vf-tl {
    top: var(--viewfinder-offset);
    left: var(--viewfinder-offset);
    border-top-width: var(--viewfinder-weight);
    border-left-width: var(--viewfinder-weight);
  }
  [data-slot="panel"][data-frame="viewfinder"] [data-slot="panel-corners"] > .vf-tr {
    top: var(--viewfinder-offset);
    right: var(--viewfinder-offset);
    border-top-width: var(--viewfinder-weight);
    border-right-width: var(--viewfinder-weight);
  }
  [data-slot="panel"][data-frame="viewfinder"] [data-slot="panel-corners"] > .vf-bl {
    bottom: var(--viewfinder-offset);
    left: var(--viewfinder-offset);
    border-bottom-width: var(--viewfinder-weight);
    border-left-width: var(--viewfinder-weight);
  }
  [data-slot="panel"][data-frame="viewfinder"] [data-slot="panel-corners"] > .vf-br {
    bottom: var(--viewfinder-offset);
    right: var(--viewfinder-offset);
    border-bottom-width: var(--viewfinder-weight);
    border-right-width: var(--viewfinder-weight);
  }
  [data-slot="panel"][data-frame="viewfinder"] [data-slot="panel-header"] {
    border-block-end: 1px solid
      var(--panel-hairline, color-mix(in oklab, var(--border) 60%, transparent));
  }
  [data-slot="panel"][data-frame="viewfinder"] [data-slot="panel-footer"] {
    border-block-start: 1px solid
      var(--panel-hairline, color-mix(in oklab, var(--border) 60%, transparent));
  }

  /* ============================================================
     Frame: surface — elevated --surface-1 background, transparent
     border (forced-colors fallback), inner top highlight.
     ============================================================ */
  [data-slot="panel"][data-frame="surface"] {
    background: var(--surface-1);
    border: 1px solid transparent;
    box-shadow: inset 0 1px 0 color-mix(in oklab, var(--foreground) 4%, transparent);
  }
  [data-slot="panel"][data-frame="surface"] [data-slot="panel-header"] {
    border-block-end: 1px solid
      var(--panel-hairline, color-mix(in oklab, var(--border) 60%, transparent));
  }
  [data-slot="panel"][data-frame="surface"] [data-slot="panel-footer"] {
    border-block-start: 1px solid
      var(--panel-hairline, color-mix(in oklab, var(--border) 60%, transparent));
  }

  /* ============================================================
     Tone — paints --panel-tone (the header marker bar) and the
     frame's color signal. Tone is a pure visual cue; semantic
     status messaging belongs in Callout (see callout.css).
     ============================================================ */
  [data-slot="panel"][data-tone="info"] {
    --panel-tone: var(--info-text);
  }
  [data-slot="panel"][data-tone="success"] {
    --panel-tone: var(--success-text);
  }
  [data-slot="panel"][data-tone="warning"] {
    --panel-tone: var(--warning-text);
  }
  [data-slot="panel"][data-tone="error"] {
    --panel-tone: var(--error-text);
  }
  [data-slot="panel"][data-tone="accent"] {
    --panel-tone: var(--action);
  }

  /* Hairline frame: border + bar adopt the tone color. */
  [data-slot="panel"][data-frame="hairline"][data-tone="info"] {
    border-color: var(--info-border);
  }
  [data-slot="panel"][data-frame="hairline"][data-tone="success"] {
    border-color: var(--success-border);
  }
  [data-slot="panel"][data-frame="hairline"][data-tone="warning"] {
    border-color: var(--warning-border);
  }
  [data-slot="panel"][data-frame="hairline"][data-tone="error"] {
    border-color: var(--error-border);
  }
  [data-slot="panel"][data-frame="hairline"][data-tone="accent"] {
    border-color: var(--action);
  }

  /* Rail frame: rail color. */
  [data-slot="panel"][data-frame="rail"][data-tone="info"] {
    border-inline-start-color: var(--info-border);
  }
  [data-slot="panel"][data-frame="rail"][data-tone="success"] {
    border-inline-start-color: var(--success-border);
  }
  [data-slot="panel"][data-frame="rail"][data-tone="warning"] {
    border-inline-start-color: var(--warning-border);
  }
  [data-slot="panel"][data-frame="rail"][data-tone="error"] {
    border-inline-start-color: var(--error-border);
  }
  [data-slot="panel"][data-frame="rail"][data-tone="accent"] {
    border-inline-start-color: var(--action);
  }

  /* Viewfinder frame: corner color. */
  [data-slot="panel"][data-frame="viewfinder"][data-tone="info"] {
    --viewfinder-color: var(--info-text);
  }
  [data-slot="panel"][data-frame="viewfinder"][data-tone="success"] {
    --viewfinder-color: var(--success-text);
  }
  [data-slot="panel"][data-frame="viewfinder"][data-tone="warning"] {
    --viewfinder-color: var(--warning-text);
  }
  [data-slot="panel"][data-frame="viewfinder"][data-tone="error"] {
    --viewfinder-color: var(--error-text);
  }
  [data-slot="panel"][data-frame="viewfinder"][data-tone="accent"] {
    --viewfinder-color: var(--action);
  }

  /* Surface frame: subtle header tint + colored bottom-border on header. */
  [data-slot="panel"][data-frame="surface"][data-tone="info"] [data-slot="panel-header"] {
    background: color-mix(in oklab, var(--info-text) 6%, transparent);
    border-block-end-color: var(--info-border);
  }
  [data-slot="panel"][data-frame="surface"][data-tone="success"] [data-slot="panel-header"] {
    background: color-mix(in oklab, var(--success-text) 6%, transparent);
    border-block-end-color: var(--success-border);
  }
  [data-slot="panel"][data-frame="surface"][data-tone="warning"] [data-slot="panel-header"] {
    background: color-mix(in oklab, var(--warning-text) 8%, transparent);
    border-block-end-color: var(--warning-border);
  }
  [data-slot="panel"][data-frame="surface"][data-tone="error"] [data-slot="panel-header"] {
    background: color-mix(in oklab, var(--error-text) 8%, transparent);
    border-block-end-color: var(--error-border);
  }
  [data-slot="panel"][data-frame="surface"][data-tone="accent"] [data-slot="panel-header"] {
    background: color-mix(in oklab, var(--action) 6%, transparent);
    border-block-end-color: var(--action);
  }
}

/* ============================================================
   Forced-colors: keep panel boundaries legible in Windows HCM.
   Rail and surface frames need an explicit perimeter cue.
   ============================================================ */
@media (forced-colors: active) {
  [data-slot="panel"][data-frame="hairline"],
  [data-slot="panel"][data-frame="surface"] {
    border-color: CanvasText;
  }
  [data-slot="panel"][data-frame="rail"] {
    border-inline-start-color: CanvasText;
  }
  [data-slot="panel"][data-frame="viewfinder"] [data-slot="panel-corners"] > span {
    border-color: CanvasText;
  }
  [data-slot="panel-header"][data-marker="bar"]::before {
    background: CanvasText;
  }
}
